import{_ as e,o as n,c as a,ag as i}from"./chunks/framework.BZohXCq9.js";const v=JSON.parse('{"title":"在离线环境使用 nvm-windows 安装和管理 node.js","description":"本文详细介绍了在离线环境中使用 nvm-windows 安装和管理 Node.js 的步骤。首先，需要提前在有网络的环境中下载 nvm-windows 安装包和所需的 Node.js 版本文件，并将其拷贝到离线环境中。接着，通过运行 `nvm-setup.exe` 完成 nvm-windows 的安装，并手动将 Node.js 版本文件解压到 nvm 的安装目录下。最后，使用 nvm 命令查看、切换和验证已安装的 Node.js 版本。通过本教程，用户可以在无网络的环境中轻松管理多个 Node.js 版本。","frontmatter":{"title":"在离线环境使用 nvm-windows 安装和管理 node.js","date":"2025-03-04T14:32:51.000Z","description":"本文详细介绍了在离线环境中使用 nvm-windows 安装和管理 Node.js 的步骤。首先，需要提前在有网络的环境中下载 nvm-windows 安装包和所需的 Node.js 版本文件，并将其拷贝到离线环境中。接着，通过运行 `nvm-setup.exe` 完成 nvm-windows 的安装，并手动将 Node.js 版本文件解压到 nvm 的安装目录下。最后，使用 nvm 命令查看、切换和验证已安装的 Node.js 版本。通过本教程，用户可以在无网络的环境中轻松管理多个 Node.js 版本。","tags":"前端 nvm 离线安装","categories":["前端"]},"headers":[],"relativePath":"posts/在离线环境使用-nvm-windows-安装和管理-node-js/index.md","filePath":"posts/在离线环境使用-nvm-windows-安装和管理-node-js/index.md","lastUpdated":null}'),o={name:"posts/在离线环境使用-nvm-windows-安装和管理-node-js/index.md"};function d(t,s,l,p,r,h){return n(),a("div",null,[...s[0]||(s[0]=[i(`<h2 id="摘要" tabindex="-1">摘要 <a class="header-anchor" href="#摘要" aria-label="Permalink to &quot;摘要&quot;">​</a></h2><p>本文详细介绍了在离线环境中使用 nvm-windows 安装和管理 Node.js 的步骤。首先，需要提前在有网络的环境中下载 nvm-windows 安装包和所需的 Node.js 版本文件，并将其拷贝到离线环境中。接着，通过运行 <code>nvm-setup.exe</code> 完成 nvm-windows 的安装，并手动将 Node.js 版本文件解压到 nvm 的安装目录下。最后，使用 nvm 命令查看、切换和验证已安装的 Node.js 版本。通过本教程，用户可以在无网络的环境中轻松管理多个 Node.js 版本。</p><h2 id="正文" tabindex="-1">正文 <a class="header-anchor" href="#正文" aria-label="Permalink to &quot;正文&quot;">​</a></h2><h3 id="离线环境安装-nvm-windows-并使用-nvm-安装和管理-node-js-的教程" tabindex="-1">离线环境安装 nvm-windows 并使用 nvm 安装和管理 Node.js 的教程 <a class="header-anchor" href="#离线环境安装-nvm-windows-并使用-nvm-安装和管理-node-js-的教程" aria-label="Permalink to &quot;离线环境安装 nvm-windows 并使用 nvm 安装和管理 Node.js 的教程&quot;">​</a></h3><h4 id="_1-准备工作" tabindex="-1">1. 准备工作 <a class="header-anchor" href="#_1-准备工作" aria-label="Permalink to &quot;1. 准备工作&quot;">​</a></h4><p>在离线环境中安装 nvm-windows 需要提前准备好所需的安装包和 Node.js 版本文件。以下是具体步骤：</p><ol><li><p><strong>下载 nvm-windows 安装包</strong>： • 在有网络的环境中，访问 <a href="https://github.com/coreybutler/nvm-windows/releases" target="_blank" rel="noreferrer">nvm-windows GitHub 仓库</a>，下载最新版本的 <code>nvm-setup.exe</code> 安装包。 • 将下载的安装包拷贝到离线环境的电脑中。</p></li><li><p><strong>下载 Node.js 版本文件</strong>： • 在有网络的环境中，访问 <a href="https://nodejs.org/dist/" target="_blank" rel="noreferrer">Node.js 官网</a>，下载所需的 Node.js 版本的 <code>.zip</code> 文件（例如 <code>node-v14.17.0-win-x64.zip</code>）。 • 将下载的 Node.js 版本文件拷贝到离线环境的电脑中。</p></li></ol><h4 id="_2-安装-nvm-windows" tabindex="-1">2. 安装 nvm-windows <a class="header-anchor" href="#_2-安装-nvm-windows" aria-label="Permalink to &quot;2. 安装 nvm-windows&quot;">​</a></h4><ol><li><p><strong>运行安装程序</strong>：</p><ul><li>在离线环境中，双击 <code>nvm-setup.exe</code>，按照安装向导完成安装。</li><li>在安装过程中，选择 nvm 的安装路径（例如 <code>C:\\nvm4w</code>）。</li></ul></li><li><p><strong>验证安装</strong>：</p><p>打开命令行，输入 <code>nvm -v</code>，如果显示 nvm 的版本号，说明安装成功。</p><div class="language-powersehll vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powersehll</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>nvm -v</span></span>
<span class="line"><span># 返回 nvm 版本号</span></span>
<span class="line"><span># 1.2.2</span></span></code></pre></div></li></ol><h4 id="_3-手动安装-node-js-版本" tabindex="-1">3. 手动安装 Node.js 版本 <a class="header-anchor" href="#_3-手动安装-node-js-版本" aria-label="Permalink to &quot;3. 手动安装 Node.js 版本&quot;">​</a></h4><ol><li><p><strong>手动安装 Node.js 版本</strong>： • 将之前下载的 Node.js 版本文件（例如 <code>node-v20.18.3-win-x64.zip</code>）解压到 nvm 的安装目录下，并改名为 <code>v20.18.3</code> 文件夹中（例如 <code>C:\\Users\\&lt;user&gt;\\AppData\\Local\\nvm</code>, 其中<code>&lt;user&gt;</code>是当前用户名）。</p></li><li><p><strong>验证</strong>：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">nvm list</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 返回已经安装的 Node.js 版本</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># * 20.18.3</span></span></code></pre></div></li></ol><h4 id="_4-管理-node-js-版本" tabindex="-1">4. 管理 Node.js 版本 <a class="header-anchor" href="#_4-管理-node-js-版本" aria-label="Permalink to &quot;4. 管理 Node.js 版本&quot;">​</a></h4><ol><li><p><strong>查看已经安装的 Node.js 版本</strong></p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">nvm list</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 返回已经安装的 Node.js 版本</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># * 20.18.3</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#   18.x.x</span></span></code></pre></div></li><li><p><strong>切换 Node.js 版本</strong></p><p>使用以下命令切换到已安装的 Node.js 版本：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">nvm use </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">20.18</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span></span></code></pre></div></li><li><p><strong>验证 Node.js 版本</strong>： • 输入 <code>node -v</code> 和 <code>npm -v</code>，查看当前使用的 Node.js 和 npm 版本，确保切换成功。</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">node </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">v</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 返回 node.js 版本号</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 20.18.3</span></span></code></pre></div></li></ol><h3 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h3><p>通过以上步骤，你可以在离线环境中成功安装并使用 nvm-windows 来管理多个 Node.js 版本。如果在安装或使用过程中遇到问题，可以参考 nvm-windows 的官方文档或社区支持。</p><h2 id="注" tabindex="-1">注 <a class="header-anchor" href="#注" aria-label="Permalink to &quot;注&quot;">​</a></h2><p>无</p><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><p>无</p>`,19)])])}const m=e(o,[["render",d]]);export{v as __pageData,m as default};
